package com.travelassistant.consultation.security;import org.springframework.stereotype.Component;import java.util.regex.Pattern;
@Component public class PrivacyRedactor{private static final Pattern EMAIL=Pattern.compile("(?i)[A-Z0-9._%+-]+@[A-Z0-9.-]+\\.[A-Z]{2,}");private static final Pattern PHONE=Pattern.compile("(?<!\\d)1[3-9]\\d{9}(?!\\d)");private static final Pattern ID=Pattern.compile("(?<!\\d)\\d{17}[0-9Xx](?!\\d)");private static final Pattern CARD=Pattern.compile("(?<!\\d)(?:\\d[ -]?){13,19}(?!\\d)");private static final Pattern KEY=Pattern.compile("(?i)(sk-[a-z0-9_-]{12,}|api[_-]?key\\s*[:=]\\s*\\S+|bearer\\s+[a-z0-9._-]{16,})");public Result redact(String input){if(KEY.matcher(input).find())throw new UnsafeContentException("SENSITIVE_CONTENT_REJECTED","请求包含不应传输的敏感凭证");String value=EMAIL.matcher(input).replaceAll("[EMAIL]");value=PHONE.matcher(value).replaceAll("[PHONE]");value=ID.matcher(value).replaceAll("[ID_NUMBER]");value=CARD.matcher(value).replaceAll("[PAYMENT_CARD]");return new Result(value,!value.equals(input));}public record Result(String content,boolean redacted){}}
